import{_ as t,o as r,c as n,a0 as s}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"📝 정처기 실기 오답노트 요약 정리 (취약 개념 중심)","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/project/정보처리기사-실기/정보처리기사-실기-오답-1회차.md","filePath":"outta-space/project/정보처리기사-실기/정보처리기사-실기-오답-1회차.md"}'),l={name:"outta-space/project/정보처리기사-실기/정보처리기사-실기-오답-1회차.md"};function g(i,o,e,a,c,d){return r(),n("div",null,[...o[0]||(o[0]=[s('<h1 id="📝-정처기-실기-오답노트-요약-정리-취약-개념-중심" tabindex="-1">📝 정처기 실기 오답노트 요약 정리 (취약 개념 중심) <a class="header-anchor" href="#📝-정처기-실기-오답노트-요약-정리-취약-개념-중심" aria-label="Permalink to &quot;📝 정처기 실기 오답노트 요약 정리 (취약 개념 중심)&quot;">​</a></h1><h2 id="_1-테스트-testing" tabindex="-1">1. 테스트 (Testing) <a class="header-anchor" href="#_1-테스트-testing" aria-label="Permalink to &quot;1. 테스트 (Testing)&quot;">​</a></h2><ul><li><strong>화이트박스 테스트 vs 블랙박스 테스트</strong><ul><li><strong>화이트박스 테스트</strong>: 소스코드의 내부 논리적인 구조를 커버하도록 테스트 케이스를 설계 (기초 경로 검사, 제어 구조 검사, <strong>조건 검사, 루프 검사, 데이터 흐름 검사</strong>).</li><li><strong>블랙박스 테스트</strong>: 내부 구조를 보지 않고 요구사항 명세서를 기반으로 기능 중심 테스트를 수행 (동치 분할 검사, <strong>경계값 분석</strong>, 원인-효과 그래프, 오류 예측, 비교 검사).</li></ul></li><li><strong>테스트 오라클의 종류와 특징</strong>: 테스트 결과를 판단하기 위한 기법으로 <strong>샘플링 오라클, 일관성 검사 오라클, 참 오라클</strong>이 존재하며, 특징으로는 <strong>제한된 검증, 수학적 기법, 자동화 기능</strong>이 있음.</li><li><strong>일반적인 테스트 프로세스 순서</strong>: 계획 → <strong>분석 및 디자인</strong> → 케이스 및 시나리오 작성 → 수행 → 결과 평가 및 보고서 작성 → 결함 추적 및 관리.</li><li><strong>단위 테스트 수행 방법</strong>: 명세 기반 테스트(블랙박스)와 구조 기반 테스트(화이트박스)로 나뉨.</li><li><strong>하향식(Top Down) 통합 테스트</strong>: 상위 모듈에서 하위 모듈 방향으로 통합하며, 깊이 우선/넓이 우선 통합법을 사용해 초기부터 시스템 구조를 시각화할 수 있음.</li><li><strong>워크스루 (Walk Through)</strong>: 프로그램을 실행하지 않고 검토 회의 전에 <strong>미리 준비된 자료를 배포</strong>하여 사전 검토를 진행하는 정적 테스트.</li></ul><h2 id="_2-sql-문법" tabindex="-1">2. SQL 문법 <a class="header-anchor" href="#_2-sql-문법" aria-label="Permalink to &quot;2. SQL 문법&quot;">​</a></h2><ul><li><strong>그룹 함수 및 조건</strong>: <code>AVG()</code> 함수를 사용할 때는 <code>GROUP BY</code>와 함께 사용해야 함.</li><li><strong>NULL 체크</strong>: <code>IS NOT NULL</code>, <code>IS NULL</code> 구문을 사용.</li><li><strong>패턴 매칭</strong>: 특정 문자열이 포함되는 조건은 <code>LIKE &#39;%길&#39;</code> 형태로 사용.</li><li><strong>범위 조건</strong>: A와 B 사이의 값은 <code>BETWEEN A AND B</code>로 지정.</li><li><strong>정렬</strong>: 내림차순 출력은 <code>ORDER BY 컬럼명 DESC</code> (오름차순은 <code>ASC</code>).</li><li><strong>DCL (권한 부여)</strong>: <code>GRANT SELECT ON 테이블명 TO 사용자명 WITH GRANT OPTION;</code> (WITH GRANT OPTION은 권한 재부여 가능 옵션).</li><li><strong>DDL (인덱스 생성)</strong>: <code>CREATE UNIQUE INDEX 인덱스명 ON 테이블(컬럼 ASC);</code>.</li><li><strong>DML (데이터 삽입)</strong>: <code>INSERT INTO 테이블(컬럼1, 컬럼2) VALUES (값1, 값2);</code>.</li><li><strong>뷰 생성</strong>: <code>CREATE VIEW 뷰명(컬럼명들) AS SELECT ...;</code>.</li><li><strong>연산자 용법</strong>: 여러 값 중 하나에 해당하는 조건은 <code>IN (1, 2, 3)</code>을 사용하며, <strong>같지 않음은 <code>&lt;&gt;</code></strong> 로 표현함.</li></ul><h2 id="_3-데이터베이스-database" tabindex="-1">3. 데이터베이스 (Database) <a class="header-anchor" href="#_3-데이터베이스-database" aria-label="Permalink to &quot;3. 데이터베이스 (Database)&quot;">​</a></h2><ul><li><strong>정규화 (Normalization) 암기 공식: &quot;도부이결다조&quot;</strong><ul><li><strong>제1정규형</strong>: <strong>도</strong>메인이 원자값</li><li><strong>제2정규형</strong>: <strong>부</strong>분 함수 종속 제거</li><li><strong>제3정규형</strong>: <strong>이</strong>행적 함수 종속 제거</li><li><strong>BCNF</strong>: <strong>결</strong>정자이면서 후보키가 아닌 함수 종속 제거 (보이스-코드 정규형)</li><li><strong>제4정규형</strong>: <strong>다</strong>치 종속 제거</li><li><strong>제5정규형</strong>: <strong>조</strong>인 종속 제거</li></ul></li><li><strong>SQL 언어의 분류</strong><ul><li><strong>DDL (데이터 정의어)</strong>: CREATE, ALTER, DROP.</li><li><strong>DML (데이터 조작어)</strong>: SELECT, INSERT, DELETE, UPDATE.</li><li><strong>DCL (데이터 제어어)</strong>: 보안, 무결성, 트랜잭션 제어를 담당하며 COMMIT, ROLLBACK, GRANT, REVOKE가 있음.</li></ul></li><li><strong>삭제 옵션 (RESTRICT)</strong>: 테이블 삭제 시 해당 테이블을 참조하는 테이블이 있다면 <strong>삭제를 취소</strong>하는 옵션.</li><li><strong>파티셔닝 분할 유형</strong>: 대용량 테이블을 나누는 기준으로 <strong>범위(Range), 해시(Hash), 조합(Composite), 목록(List)</strong> 분할이 있음.</li><li><strong>관계대수 (디비전, <code>÷</code>)</strong>: B 릴레이션의 모든 조건을 만족하는 튜플을 A에서 분리해 프로젝션하는 연산 기호.</li><li><strong>반정규화</strong>: 성능 향상과 운영 단순화를 위해 정규화된 엔터티, 속성 등을 <strong>중복, 통합, 분리</strong>하는 기법.</li></ul><h2 id="_4-보안-security" tabindex="-1">4. 보안 (Security) <a class="header-anchor" href="#_4-보안-security" aria-label="Permalink to &quot;4. 보안 (Security)&quot;">​</a></h2><ul><li><strong>정보보호의 5대 목표 (무기가인책)</strong>: 기밀성, 무결성, 가용성, <strong>인증성, 책임성</strong>.</li><li><strong>컴퓨터 바이러스 공격 유형</strong>: 가로막기, 가로채기, <strong>수정, 위조</strong>.</li><li><strong>접근 통제 정책</strong><ul><li><strong>MAC (강제적)</strong>: 시스템이 보안 등급을 기준으로 부여.</li><li><strong>DAC (임의적)</strong>: 데이터 소유자가 신분을 기준으로 부여.</li><li><strong>RBAC (역할 기반)</strong>: 중앙 관리자가 역할을 기준으로 부여.</li></ul></li><li><strong>암호화 및 보안 기술</strong><ul><li><strong>Hash (해시)</strong>: 임의의 길이 입력을 고정된 길이의 값이나 키로 변환.</li><li><strong>블록 암호</strong>: 평문을 일정한 블록 단위로 나누어 암호화.</li><li><strong>스트림 암호</strong>: 비트/바이트 단위로 난수 초기값을 발생시켜 XOR 연산 수행 (빠르고 오류 영향 적음).</li><li><strong>시큐어 코딩</strong>: 초기 설계 단계부터 보안 취약점을 사전에 제거하도록 코딩하는 방식.</li></ul></li><li><strong>버퍼 오버플로우 방지 기법</strong>: 복귀 주소와 변수 사이에 특정 값을 저장하는 <strong>스택 가드</strong>, 함수 종료 시 복사본과 비교하는 <strong>스택 실드</strong>.</li><li><strong>바이러스/악성코드 개념</strong><ul><li><strong>그레이웨어 (Grayware)</strong>: 유용하지 않거나 악의적일 수 있는 애드웨어, 스파이웨어 등 악성 소프트웨어의 총칭.</li><li><strong>바이러스 감염 위치별 분류</strong>: 부트, 파일, 매크로, 메모리 상주.</li><li><strong>IPS (침입 차단 시스템)</strong>: 내부 네트워크 보호를 위해 외부 침입을 통제하는 시스템.</li></ul></li></ul><h2 id="_5-프로그래밍-programming" tabindex="-1">5. 프로그래밍 (Programming) <a class="header-anchor" href="#_5-프로그래밍-programming" aria-label="Permalink to &quot;5. 프로그래밍 (Programming)&quot;">​</a></h2><ul><li><strong>C언어 연산자 우선순위</strong>: 덧셈(<code>+</code>) 연산자가 동등 비교(<code>==</code>) 연산자보다 우선순위가 높음.</li><li><strong>객체지향 및 Java 개념</strong><ul><li><strong>상속과 메서드 호출</strong>: 상위 클래스의 인스턴스로는 하위 클래스에만 정의된 메서드를 호출할 수 없음.</li><li><strong>Encapsulation (캡슐화)</strong>: 내부 변수 접근을 <code>private</code>로 막고 메서드를 통해 접근하게 하는 기법.</li><li><strong>this 와 super</strong>: 내 객체의 필드 접근은 <code>this.필드 = 매개변수</code>, 부모 클래스 생성자 호출은 <code>super(인수)</code> 사용.</li><li><strong>오버라이딩</strong>: 부모에게 상속받은 메서드를 자식 클래스에서 재정의하는 기술.</li></ul></li><li><strong>Python 특징</strong><ul><li><strong>self</strong>: 클래스 메서드 내부에서 객체 자신을 지칭할 때 사용.</li><li><strong>들여쓰기</strong>: 중괄호 <code>{}</code> 대신 코드의 지역(블록)을 구분할 때 사용.</li></ul></li></ul><h2 id="_6-운영체제-os" tabindex="-1">6. 운영체제 (OS) <a class="header-anchor" href="#_6-운영체제-os" aria-label="Permalink to &quot;6. 운영체제 (OS)&quot;">​</a></h2><ul><li><strong>운영체제 스케줄링 및 상태</strong><ul><li><strong>프로세스 상태 전이</strong>: 준비→실행(<strong>Dispatch</strong>), 실행→준비(<strong>Time Run Out</strong>), 실행→대기(<strong>Block</strong>), 대기→준비(<strong>Wake Up</strong>).</li><li><strong>비선점형 스케줄링</strong>: 강제 중단이 불가능한 방식으로 <strong>FIFO, SJF, HRN</strong>이 있음.</li></ul></li><li><strong>교착상태 (Deadlock)</strong><ul><li><strong>발생 조건</strong>: 상호 배제, 점유와 대기, 비선점, 환형 대기.</li><li><strong>회복 시 희생양 기준</strong>: 우선순위가 낮거나, 진행률이 적거나, 자원을 적게 쓰거나, 무한 대기 등으로 수행 불가능한 프로세스.</li></ul></li><li><strong>메모리 및 자원 관리</strong><ul><li><strong>오버레이 기법</strong>: 주기억장치보다 큰 프로그램을 실행하기 위해 프로그램을 조각내어 프로그래머가 직접 메모리에 적재하는 기법.</li><li><strong>스와핑</strong>: 보조기억장치에서 주기억장치로 불러오는 <strong>Swap In</strong>, 반대로 내보내는 <strong>Swap Out</strong>.</li><li><strong>레지스터</strong>: **제어장치(CU)**는 명령어 수행 데이터 저장, **연산장치(ALU)**는 산술/논리 연산 수행.</li></ul></li><li><strong>유닉스(Unix)</strong>: C언어 기반, 높은 이식성, 다중 사용자 지원. 핵심 요소로 <strong>커널, 쉘, 유틸리티</strong>가 있음.</li><li><strong>커널의 종류</strong>: 최소 기능만 담은 <strong>마이크로 커널</strong>, 동적 적재가 불가하지만 빠르고 구현이 간단한 <strong>모놀리식 커널</strong>.</li><li><strong>쉘 스크립트</strong>: 여러 제어 명령을 자동으로 실행할 수 있는 인터프리터 방식의 프로그램 (<code>.sh</code>).</li></ul><h2 id="_7-네트워크-network" tabindex="-1">7. 네트워크 (Network) <a class="header-anchor" href="#_7-네트워크-network" aria-label="Permalink to &quot;7. 네트워크 (Network)&quot;">​</a></h2><ul><li><strong>OSI 7계층 암기</strong><ul><li><strong>상위 3계층</strong>: 응용, 표현, <strong>세션 계층</strong>.</li><li><strong>하위 4계층</strong>: 전송, 네트워크, <strong>데이터링크, 물리 계층</strong>.</li><li><strong>데이터링크 계층</strong>: MAC 주소 사용, Frame 단위 전송, 신뢰성 있는 노드 간 전송 및 오류/흐름 제어.</li><li><strong>물리 계층 장비</strong>: 통신 케이블, 허브, 리피터.</li></ul></li><li><strong>IP 및 주소 체계</strong><ul><li><strong>서브넷 마스크</strong>: 고정된 크기 분할은 <strong>FLSM</strong>, 다양한 크기 분할은 <strong>VLSM</strong>.</li><li><strong>도메인 네임 (Domain Name)</strong>: 숫자 IP를 외우기 쉽게 문자 형태로 변환한 주소.</li><li><strong>CIDR / DHCP</strong>: 클래스를 무시하고 유연하게 IP를 할당하거나 동적으로 할당하는 프로토콜.</li><li><strong>ARP / RARP</strong>: IP를 MAC 주소로 변환하는 것은 ARP, 그 반대(MAC을 IP로)는 RARP.</li></ul></li><li><strong>네트워크 통신망 및 프로토콜</strong><ul><li><strong>버스 종류</strong>: 외부 버스는 <strong>주소 버스, 데이터 버스, 제어 버스</strong>로 나뉨.</li><li><strong>TCP 제어 비트 (플래그)</strong>: 연결을 처음 개설할 때 사용하는 제어 비트는 <strong>SYN</strong>.</li><li><strong>전자우편 (Email)</strong>: SMTP, POP3, MIME, IMAP.</li><li><strong>FTP</strong>: 업로드/다운로드를 지원하며 ASCII와 Binary 전송 모드를 가짐.</li><li><strong>SNMP</strong>: 장비 관리 감시를 위한 UDP 기반 응용 계층 프로토콜.</li><li><strong>RTP</strong>: 실시간 오디오/비디오(스트리밍) 전달 프로토콜.</li></ul></li><li><strong>변조 방식</strong>: 1과 0을 위상 차이로 전송하는 방식은 <strong>위상 편이 변조 (PSK)</strong>.</li></ul><h2 id="_8-it-신기술-및-소프트웨어-공학-용어" tabindex="-1">8. IT 신기술 및 소프트웨어 공학 용어 <a class="header-anchor" href="#_8-it-신기술-및-소프트웨어-공학-용어" aria-label="Permalink to &quot;8. IT 신기술 및 소프트웨어 공학 용어&quot;">​</a></h2><ul><li><strong>개념 및 방법론</strong><ul><li><strong>클린 코드 원칙</strong>: 중복 최소화를 위해 <strong>가독성, 단순성, 의존성 배제, 중복성 제거, 추상화</strong> 원칙을 따름.</li><li><strong>분산 시스템 투명성</strong>: 위치, 중복, 병행, 장애 투명성.</li></ul></li><li><strong>IT 신기술 용어</strong><ul><li><strong>SOA (서비스 지향 아키텍처)</strong>: 소프트웨어 인프라를 재사용 가능한 서비스 단위로 구축.</li><li><strong>DRM (디지털 저작권 관리)</strong>: 디지털 콘텐츠의 안전한 배포 및 저작권 보호 시스템.</li><li><strong>TrustZone</strong>: 프로세서 내 일반 구역과 보안 구역을 물리적으로 분리하는 기술.</li><li><strong>N-Screen</strong>: 여러 단말기에서 동일 콘텐츠를 이어서 볼 수 있는 서비스.</li><li><strong>Thin Client PC</strong>: 하드디스크 없이 메모리만 갖추고 서버 네트워크로 동작하는 PC.</li><li><strong>데이터 기술</strong>: 데이터를 분석하기 좋게 축적하는 <strong>Data Warehouse</strong>, 방대한 상호작용 데이터인 <strong>Broad Data</strong>, 데이터를 설명하는 <strong>Meta Data</strong>, 불필요한 데이터를 압축하여 분리 보관하는 <strong>Data Diet</strong>, 웹상 무료 공개 데이터인 <strong>Linked Open Data</strong> 등.</li><li><strong>디지털 아카이빙</strong>: 아날로그/디지털 자원을 변환, 압축, 메타데이터화 하여 장기 보존.</li><li><strong>Hadoop / Tajo</strong>: 대규모 분산 데이터 처리를 위한 자바 프레임워크(Hadoop)와 국내 주도의 SQL 기반 분산 DW 프로젝트(Tajo).</li><li><strong>하드웨어 및 네트워크 기술</strong>: 전원 없이 상태를 기억하는 <strong>멤리스터 (Memristor)</strong>, 위아래 구분 없는 <strong>C-Type USB</strong>, 조각 방식으로 영구 보관하는 <strong>M-DISC</strong>, 대규모 무선 디바이스 최적화 기술 <strong>Mesh Network</strong>, 스마트폰 근거리 무선 인식 <strong>비콘 (Beacon)</strong>, 블루투스/UWB 기반 소규모 무선 통신망 <strong>PICONET</strong>, 발행-구독 기반 경량 IoT 통신 프로토콜 <strong>MQTT</strong>.</li></ul></li></ul><h2 id="_9-추가-도부이결다조" tabindex="-1">9. (추가) 도부이결다조 <a class="header-anchor" href="#_9-추가-도부이결다조" aria-label="Permalink to &quot;9. (추가) 도부이결다조&quot;">​</a></h2><ul><li>도 (제1정규형, 1NF) : 도메인이 원자값 릴레이션에 속한 모든 속성과 도메인이 더 이상 분해할 수 없는 원자값만 가지도록 테이블을 분해한 상태를 의미합니다.</li><li>부 (제2정규형, 2NF) : 부분 함수 종속 제거 제1정규형을 만족하는 상태에서 부분 함수 종속을 제거한 릴레이션 스키마입니다. 기본키가 아닌 모든 속성들이 기본키에 완전 함수 종속 관계를 갖도록 기본키를 중심으로 릴레이션을 분해합니다.</li><li>이 (제3정규형, 3NF) : 이행적 함수 종속 제거 제2정규형을 만족하면서 이행적 함수 종속(Transitive Dependency)을 제거한 상태입니다. 결정자이자 종속자에 해당하는 속성을 기준으로 릴레이션을 분할합니다.</li><li>결 (BCNF, 보이스-코드 정규형) : 결정자이면서 후보키가 아닌 종속 제거 제3정규형을 만족하면서, 결정자가 후보키가 아닌 함수 종속을 제거한 상태입니다. 이 단계에서는 릴레이션에 존재하는 모든 결정자가 후보키인 조건을 만족해야 합니다.</li><li>다 (제4정규형, 4NF) : 다치 종속 제거 BCNF를 만족하면서, 둘 이상의 속성을 가진 결정자에 의해 정해지는 다치 종속(Multi-Valued Dependency)을 제거한 릴레이션 스키마입니다.</li><li>조 (제5정규형, 5NF) : 조인 종속 제거 제4정규형을 만족하면서, 후보키를 통하지 않은 조인 종속(Join Dependency)을 제거한 상태입니다. 릴레이션에 존재하는 모든 조인 종속성이 릴레이션의 후보키를 통해서만 성립되도록 분해 전 릴레이션으로 재구성될 수 있게 만듭니다.</li></ul>',19)])])}const T=t(l,[["render",g]]);export{h as __pageData,T as default};
